import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, PointElement, LineElement, Title, Tooltip, Legend);

const PriceAnalytics = () => {
  const [productData, setProductData] = useState([]);
  const [categoryData, setCategoryData] = useState([]);
  const [range, setRange] = useState("weekly");

  useEffect(() => {
    fetchTrends();
  }, [range]);

  const fetchTrends = async () => {
    try {
      const [prodRes, catRes] = await Promise.all([
        axios.get(`http://localhost:7000/api/price-report/trends?type=product&range=${range}`),
        axios.get(`http://localhost:7000/api/price-report/trends?type=category&range=${range}`),
      ]);

      setProductData(prodRes.data);
      setCategoryData(catRes.data);
    } catch (err) {
      console.error(err);
    }
  };

  const lineChartData = {
    labels: [...new Set(productData.flatMap((d) => d.prices.map((p) => p.date)))],
    datasets: productData.map((p, i) => ({
      label: p._id,
      data: p.prices.map((pr) => pr.avgPrice),
      borderColor: `hsl(${i * 50}, 70%, 50%)`,
      tension: 0.3,
      fill: false,
    })),
  };

  const barChartData = {
    labels: [...new Set(categoryData.flatMap((d) => d.prices.map((p) => p.date)))],
    datasets: categoryData.map((c, i) => ({
      label: c._id,
      data: c.prices.map((pr) => pr.avgPrice),
      backgroundColor: `hsl(${i * 60}, 70%, 60%)`,
    })),
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-6 text-center">📊 Price Analytics Dashboard</h2>

      <div className="flex justify-center mb-4">
        <select
          value={range}
          onChange={(e) => setRange(e.target.value)}
          className="border p-2 rounded-md"
        >
          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white shadow-lg p-4 rounded-2xl">
          <h3 className="text-lg font-semibold mb-3 text-center">📈 Product-wise Price Trends</h3>
          <Line data={lineChartData} />
        </div>

        <div className="bg-white shadow-lg p-4 rounded-2xl">
          <h3 className="text-lg font-semibold mb-3 text-center">📉 Category-wise Price Trends</h3>
          <Bar data={barChartData} />
        </div>
      </div>
    </div>
  );
};

export default PriceAnalytics;
